  const { slug } = await params
  const data = casedetails[slug]
  if (!data) return {}

  return {
    title: `${data.bedrijf} — case — iknowright`,
    description: `case study: hoe iknowright ${data.bedrijf} hielp met tiktok-content.`,
  }
}

