function forminput({
  placeholder,
  type = 'text',
  multiline = false,
  value,
  onchange,
}: {
  placeholder: string
  type?: string
  multiline?: boolean
  value: string
  onchange: (value: string) => void
}) {
  const fieldstyle: react.cssproperties = {
    ...bodyfont,
    width: '100%',
    fontsize: 'clamp(0.875rem, 1.39vw, 20px)',
    color: ikr.navytext,
