    borderradius: 16,
    padding: 'clamp(14px, 1.6vw, 22px) clamp(16px, 1.9vw, 28px)',
    outline: 'none',
    resize: 'none' as const,
  }

  if (multiline) {
    return (
      <textarea
        placeholder={placeholder}
        rows={5}
        style={fieldstyle}
        value={value}
        onchange={(e) => onchange(e.target.value)}
      />
    )
  }

  return (
    <input
      type={type}
      placeholder={placeholder}
      style={fieldstyle}
      value={value}
      onchange={(e) => onchange(e.target.value)}
    />
  )
}

