function casevideocard({
  src,
  clientname,
  logo,
  slug,
}: {
  src: string
  clientname: string
  logo?: string
  slug: string
}) {
  const videoref = useref<htmlvideoelement>(null)
  const [hovered, sethovered] = usestate(false)

  const handleenter = () => {
    sethovered(true)
    videoref.current?.play().catch(() => {})
  }

  const handleleave = () => {
    sethovered(false)
    const video = videoref.current
    if (!video) return
    video.pause()
    video.currenttime = 0
  }

