          zindex: 2,
          pointerevents: 'none',
        }}
      >
        <arrowicon size={24} />
      </div>
    </>
  )

  const shellstyle = {
    position: 'relative' as const,
    aspectratio: '9 / 16',
    borderradius: 'clamp(18px, 2vw, 28px)',
    overflow: 'hidden' as const,
    backgroundcolor: '#d0c8bc',
    flexshrink: 0,
    cursor: 'pointer',
    display: 'block',
    textdecoration: 'none',
  }

  const hoverhandlers = {
    onmouseenter: () => videoref.current?.play().catch(() => {}),
